mapper.select:
SELECT EMP_CODE AS empCode, EMP_NAME AS empName
FROM HRIMASTER01
WHERE COMPANY   = #{company}
  AND DEPT_CODE = #{deptCode}
  AND RETIRE_DATE IS NULL
ORDER BY EMP_CODE

SELECT YYYYMMDD          AS yyyymmdd,
       ACTUAL_SHIFT_CODE AS actualShiftCode,
       LEFT(CONVERT(VARCHAR(8), CHECK_IN,  108), 5) AS checkIn,
       LEFT(CONVERT(VARCHAR(8), CHECK_OUT, 108), 5) AS checkOut,
       WORK_MIN          AS workMin,
       OVERNIGHT_YN      AS overnightYn
FROM HRTDAILYATTENDANCE01
WHERE COMPANY  = #{company}
  AND EMP_CODE = #{empCode}
  AND YYYYMMDD BETWEEN #{startYmd} AND #{endYmd}
